from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/divide/<int:a>/<int:b>')
def divide(a, b):
    if b == 0:
        return jsonify({'error': 'Division by zero'}), 400
    return jsonify({'result': a / b})

if __name__ == '__main__':
    app.run(debug=True)

